export const typeDefs = `
  type Query {
    user(id: ID!): User
    users(page: Int = 1, limit: Int = 20): UserConnection!
    post(id: ID!): Post
    posts(page: Int = 1, limit: Int = 20): PostConnection!
  }

  type Mutation {
    createPost(input: CreatePostInput!): Post!
    createComment(postId: ID!, body: String!): Comment!
    deletePost(id: ID!): Boolean!
  }

  type User {
    id: ID!
    name: String!
    email: String!
    posts(limit: Int = 10): [Post!]!
    createdAt: String!
  }

  type Post {
    id: ID!
    title: String!
    body: String!
    author: User!
    comments(limit: Int = 20): [Comment!]!
    commentCount: Int!
    createdAt: String!
  }

  type Comment {
    id: ID!
    body: String!
    author: User!
    createdAt: String!
  }

  type UserConnection {
    nodes: [User!]!
    total: Int!
    page: Int!
    totalPages: Int!
  }

  type PostConnection {
    nodes: [Post!]!
    total: Int!
    page: Int!
    totalPages: Int!
  }

  input CreatePostInput {
    title: String!
    body: String!
  }
`;

import DataLoader from 'dataloader';
import { db } from './db';

export function createLoaders() {
  return {
    userById: new DataLoader<number, any>(async (ids) => {
      const users = await db('users').whereIn('id', ids as number[]);
      const map = new Map(users.map(u => [u.id, u]));
      return ids.map(id => map.get(id) ?? null);
    }),
    commentsByPost: new DataLoader<number, any[]>(async (postIds) => {
      const comments = await db('comments')
        .whereIn('post_id', postIds as number[])
        .orderBy('created_at', 'asc');
      const grouped = new Map<number, any[]>();
      for (const c of comments) {
        const list = grouped.get(c.post_id) ?? [];
        list.push(c);
        grouped.set(c.post_id, list);
      }
      return postIds.map(id => grouped.get(id) ?? []);
    })
  };
}

